#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph edge
typedef struct Edge {
    int src, dest, weight;
} Edge;

// Function to perform topological sort
void topoSort(int node, int visited[], int stack[], Edge edges[], int *top, int N) {
    visited[node] = 1;
    for (int i = 0; i < N; i++) {
        if (edges[i].src == node && !visited[edges[i].dest]) {
            topoSort(edges[i].dest, visited, stack, edges, top, N);
        }
    }
    stack[(*top)++] = node;
}

// Function to find shortest distances using topological sort
void shortestPath(int N, int M, Edge edges[]) {
    int visited[N], stack[N], top = 0, dist[N];
    for (int i = 0; i < N; i++) {
        visited[i] = 0;
        dist[i] = -1;
    }
    dist[0] = 0;
    for (int i = 0; i < N; i++) {
        if (!visited[i]) {
            topoSort(i, visited, stack, edges, &top, N);
        }
    }
    for (int i = top - 1; i >= 0; i--) {
        for (int j = 0; j < M; j++) {
            if (edges[j].src == stack[i] && dist[edges[j].dest] == -1) {
                dist[edges[j].dest] = dist[edges[j].src] + edges[j].weight;
            }
        }
    }
    for (int i = 0; i < N; i++) {
        printf("%d ", dist[i]);
    }
}

int main() {
    int N, M;
    scanf("%d %d", &N, &M);
    Edge edges[M];
    for (int i = 0; i < M; i++) {
        scanf("%d %d %d", &edges[i].src, &edges[i].dest, &edges[i].weight);
    }
    shortestPath(N, M, edges);
    return 0;
}

